// mm/src/pages/register.js
import React, { useMemo, useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';

const API_BASE = process.env.REACT_APP_API_BASE_URL || '';
const DEFAULT_BASE = 'https://manuscriptmagic.fowkes.xyz/services';

const ACCESS_KEY = 'mm_accessToken';
const REFRESH_KEY = 'mm_refreshToken';
const USERID_KEY = 'mm_userId';

function isValidEmail(email) {
  const v = String(email || '').trim();
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
}

export default function RegisterPage() {
  const nav = useNavigate();

  const [form, setForm] = useState({
    email: '',
    password: '',
    firstName: '',
    lastName: '',
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');

  const canSubmit = useMemo(() => {
    const fn = String(form.firstName || '').trim();
    const ln = String(form.lastName || '').trim();
    const em = String(form.email || '').trim();
    const pw = String(form.password || '');
    return fn.length > 0 && ln.length > 0 && isValidEmail(em) && pw.length >= 8 && !loading;
  }, [form, loading]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    setLoading(true);
    setError('');
    setSuccessMessage('');

    const payload = {
      firstName: String(form.firstName || '').trim(),
      lastName: String(form.lastName || '').trim(),
      email: String(form.email || '').trim(),
      password: String(form.password || ''),
    };

    if (!payload.firstName) {
      setLoading(false);
      setError('First name is required.');
      return;
    }
    if (!payload.lastName) {
      setLoading(false);
      setError('Last name is required.');
      return;
    }
    if (!isValidEmail(payload.email)) {
      setLoading(false);
      setError('Please enter a valid email.');
      return;
    }
    if (payload.password.length < 8) {
      setLoading(false);
      setError('Password must be at least 8 characters.');
      return;
    }

    const base = API_BASE || DEFAULT_BASE;

    try {
      const resp = await fetch(`${base}/register.php`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      let data = null;
      try {
        data = await resp.json();
      } catch {
        data = null;
      }

      if (!resp.ok || data?.success === false) {
        const msg = data?.message || data?.error || `Registration failed (${resp.status}).`;
        throw new Error(msg);
      }

      setSuccessMessage(data?.message || 'Account created successfully.');

      // ✅ AUTO SIGN-IN: store tokens if your backend returns them
      const userId = data?.userId || data?.UserId || '';
      const accessToken = data?.accessToken || data?.AccessToken || '';
      const refreshToken = data?.refreshToken || data?.RenewalToken || data?.renewalToken || '';

      if (accessToken && refreshToken) {
        if (userId) localStorage.setItem(USERID_KEY, String(userId));
        localStorage.setItem(ACCESS_KEY, String(accessToken));
        localStorage.setItem(REFRESH_KEY, String(refreshToken));

        // go to account/dashboard
        nav('/documents');
        return;
      }

      // If backend doesn't return tokens yet, fallback to login
      setSuccessMessage((prev) => prev || 'Account created. Please sign in.');
      setTimeout(() => nav('/login'), 900);
    } catch (err) {
      setError(err?.message || 'An error occurred. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-slate-50 to-slate-100 flex items-center justify-center px-4 py-12">
      <div className="w-full max-w-xl bg-white border border-slate-200 rounded-2xl shadow-sm p-8">
        <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">Create your account</h1>

        <p className="mt-2 text-slate-500">Enter your details to register.</p>

        <form onSubmit={handleSubmit} className="mt-8 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-700">
                First Name <span className="text-red-500">*</span>
              </label>
              <input
                name="firstName"
                value={form.firstName}
                onChange={handleChange}
                placeholder="First name"
                className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 focus:ring-2 focus:ring-blue-200"
                autoComplete="given-name"
                required
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700">
                Last Name <span className="text-red-500">*</span>
              </label>
              <input
                name="lastName"
                value={form.lastName}
                onChange={handleChange}
                placeholder="Last name"
                className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 focus:ring-2 focus:ring-blue-200"
                autoComplete="family-name"
                required
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700">
              Email <span className="text-red-500">*</span>
            </label>
            <input
              type="email"
              name="email"
              value={form.email}
              onChange={handleChange}
              placeholder="you@email.com"
              className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 focus:ring-2 focus:ring-blue-200"
              autoComplete="email"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700">
              Password <span className="text-red-500">*</span>
            </label>
            <input
              type="password"
              name="password"
              value={form.password}
              onChange={handleChange}
              placeholder="At least 8 characters"
              className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 focus:ring-2 focus:ring-blue-200"
              autoComplete="new-password"
              required
              minLength={8}
            />
          </div>

          {error ? <div className="text-sm text-red-600">{error}</div> : null}
          {successMessage ? <div className="text-sm text-emerald-700">{successMessage}</div> : null}

          <button
            type="submit"
            disabled={!canSubmit}
            className={[
              'w-full py-3 rounded-md text-white font-semibold',
              canSubmit ? 'bg-blue-600 hover:bg-blue-700' : 'bg-slate-300 cursor-not-allowed',
            ].join(' ')}
          >
            {loading ? 'Creating account…' : 'Register'}
          </button>

          <div className="text-sm text-slate-600 text-center">
            Already have an account?{' '}
            <Link to="/login" className="text-blue-700 hover:underline">
              Sign in
            </Link>
          </div>

          {!API_BASE ? (
            <div className="text-xs text-slate-500 text-center">
              API: using default backend (<code>{DEFAULT_BASE}</code>)
            </div>
          ) : (
            <div className="text-xs text-slate-500 text-center">
              API base: <code>{API_BASE}</code>
            </div>
          )}
        </form>
      </div>
    </div>
  );
}
